import{_ as t,c as o,o as a,ae as r}from"./chunks/framework.B7Y1jjX-.js";const k=JSON.parse('{"title":"使用自定义Hook复用逻辑","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/库/React/4Escape Hatches/8使用自定义Hook复用逻辑.md","filePath":"generated-notes/前端/库/React/4Escape Hatches/8使用自定义Hook复用逻辑.md"}'),s={name:"generated-notes/前端/库/React/4Escape Hatches/8使用自定义Hook复用逻辑.md"};function n(c,e,h,i,l,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="使用自定义hook复用逻辑" tabindex="-1">使用自定义Hook复用逻辑 <a class="header-anchor" href="#使用自定义hook复用逻辑" aria-label="Permalink to &quot;使用自定义Hook复用逻辑&quot;">​</a></h1><p>看的比较快，闲的时候再看一遍 <a href="https://zh-hans.react.dev/learn/reusing-logic-with-custom-hooks" target="_blank" rel="noreferrer">使用自定义 Hook 复用逻辑 – React 中文文档</a></p><h3 id="hook-的名称必须永远以-use-开头" tabindex="-1">Hook 的名称必须永远以 <code>use</code> 开头 <a href="https://zh-hans.react.dev/learn/reusing-logic-with-custom-hooks#hook-names-always-start-with-use" title="Link for this heading" target="_blank" rel="noreferrer"></a> <a class="header-anchor" href="#hook-的名称必须永远以-use-开头" aria-label="Permalink to &quot;Hook 的名称必须永远以 `use` 开头 [](https://zh-hans.react.dev/learn/reusing-logic-with-custom-hooks#hook-names-always-start-with-use &quot;Link for this heading&quot;)&quot;">​</a></h3><p>React 应用是由组件构成，而组件由内置或自定义 Hook 构成。可能你经常使用别人写的自定义 Hook，但偶尔也要自己写！</p><p>你必须遵循以下这些命名公约：</p><ol><li><strong>React 组件名称必须以大写字母开头</strong>，比如 <code>StatusBar</code> 和 <code>SaveButton</code>。React 组件还需要返回一些 React 能够显示的内容，比如一段 JSX。</li><li><strong>Hook 的名称必须以 <code>use</code> 开头，然后紧跟一个大写字母</strong>，就像内置的 <a href="https://zh-hans.react.dev/reference/react/useState" target="_blank" rel="noreferrer"><code>useState</code></a> 或者本文早前的自定义 <code>useOnlineStatus</code> 一样。Hook 可以返回任意值。</li><li>组件和自定义 Hook 都 <a href="https://zh-hans.react.dev/learn/keeping-components-pure" target="_blank" rel="noreferrer">需要是纯函数</a></li></ol><p>如果你为 <a href="https://zh-hans.react.dev/learn/editor-setup#linting" target="_blank" rel="noreferrer">React 配置了</a> 代码检查工具，它会强制执行这个命名公约。现在滑动到上面的 sandbox，并将 <code>useOnlineStatus</code> 重命名为 <code>getOnlineStatus</code>。注意此时代码检查工具将不会再允许你在其内部调用 <code>useState</code> 或者 <code>useEffect</code>。只有 Hook 和组件可以调用其他 Hook！</p><h4 id="渲染期间调用的所有函数都应该以-use-前缀开头么" tabindex="-1">渲染期间调用的所有函数都应该以 use 前缀开头么？ <a href="https://zh-hans.react.dev/learn/reusing-logic-with-custom-hooks#should-all-functions-called-during-rendering-start-with-the-use-prefix" title="Link for 渲染期间调用的所有函数都应该以 use 前缀开头么？" target="_blank" rel="noreferrer"></a> <a class="header-anchor" href="#渲染期间调用的所有函数都应该以-use-前缀开头么" aria-label="Permalink to &quot;渲染期间调用的所有函数都应该以 use 前缀开头么？ [](https://zh-hans.react.dev/learn/reusing-logic-with-custom-hooks#should-all-functions-called-during-rendering-start-with-the-use-prefix &quot;Link for 渲染期间调用的所有函数都应该以 use 前缀开头么？&quot;)&quot;">​</a></h4><p>不。没有 <strong>调用</strong> Hook 的函数不需要 <strong>变成</strong> Hook。</p><p>如果你创建的函数没有调用任何 Hook 方法，在命名时应避免使用 <code>use</code> 前缀，把它当成一个常规函数去命名。</p>',10)])])}const p=t(s,[["render",n]]);export{k as __pageData,p as default};
